record.field:
for record in records:
    if record['x_status_bar'] == 'done':
        record['website_published'] = False
    if record['x_status_bar'] == 'draft':
        if record['website_published']:
            raise UserError("You cannot publish a Draft Job Position.")
        if record.all_application_count > 0:
            raise UserError("You cannot set this job position back to Draft because applications already exist.")

for cv in records:
    cv['x_is_published'] = False
    cv.x_applicant_id.write({'x_published': False})

jobs = records.mapped('x_job_position_ids').filtered(lambda job: job.active)
action = {
    'res_model': 'hr.job',
    'type': 'ir.actions.act_window',
}
if jobs:
    action.update({'view_mode': 'form', 'res_id': jobs.id} if len(jobs) == 1 else {'view_mode': 'list,form', 'domain': [('id', 'in', jobs.ids)]})

applicants = env['hr.applicant'].search([('x_opportunities', 'in', records.ids)])
action = {
    'res_model': 'hr.applicant',
    'type': 'ir.actions.act_window',
}
if applicants:
    action.update({'view_mode': 'form', 'res_id': applicants.id} if len(applicants) == 1 else {'view_mode': 'list,form', 'domain': [('id', 'in', applicants.ids)]})

action = {
    'view_mode': 'form',
    'type': 'ir.actions.act_window',
    'res_model': 'hr.job',
    'context': {
        'default_x_opportunity_id': record.id,
        'default_x_customer_id': record.partner_id.id if record.partner_id else False,
    }
}

action = {
    'view_mode': 'form',
    'type': 'ir.actions.act_window',
    'res_model': 'sale.order',
    'context': {
        'default_x_job_id': record.id,
        'default_partner_id': record.x_customer_id.id if record.x_customer_id else False,
        'default_opportunity_id': record.x_opportunity_id.id if record.x_opportunity_id else False,
    }
}
